import java.util.*;

public class SlidingWindow {

    // ── FIXED WINDOW: Max sum of k consecutive elements ─────────
    static int maxSumFixed(int[] arr, int k) {
        int windowSum = 0;
        for (int i = 0; i < k; i++) windowSum += arr[i]; // first window
        int maxSum = windowSum;
        for (int r = k; r < arr.length; r++) {
            windowSum += arr[r] - arr[r - k]; // slide: add new, remove old
            maxSum = Math.max(maxSum, windowSum);
        }
        return maxSum;
    }

    // ── VARIABLE WINDOW: Longest substring without repeating chars
    static int longestUniqueSubstring(String s) {
        Map<Character, Integer> lastSeen = new HashMap<>();
        int maxLen = 0, l = 0;
        for (int r = 0; r < s.length(); r++) {
            char c = s.charAt(r);
            if (lastSeen.containsKey(c) && lastSeen.get(c) >= l) {
                l = lastSeen.get(c) + 1; // shrink: move l past duplicate
            }
            lastSeen.put(c, r);
            maxLen = Math.max(maxLen, r - l + 1);
        }
        return maxLen;
    }

    // ── VARIABLE WINDOW: Minimum window size with sum >= target
    static int minSubarrayLen(int target, int[] nums) {
        int l = 0, sum = 0, minLen = Integer.MAX_VALUE;
        for (int r = 0; r < nums.length; r++) {
            sum += nums[r];
            while (sum >= target) { // window is valid — try to shrink
                minLen = Math.min(minLen, r - l + 1);
                sum -= nums[l++];
            }
        }
        return minLen == Integer.MAX_VALUE ? 0 : minLen;
    }

    public static void main(String[] args) {
        System.out.println(maxSumFixed(new int[]{2,1,5,1,3,2}, 3));    // 9 (5+1+3)
        System.out.println(longestUniqueSubstring("abcabcbb"));         // 3 (abc)
        System.out.println(longestUniqueSubstring("pwwkew"));           // 3 (wke)
        System.out.println(minSubarrayLen(7, new int[]{2,3,1,2,4,3})); // 2 (4+3)
    }
}

import java.util.*;

public class TwoPointersPrefixSum {

    // ── TWO POINTERS: Two Sum in sorted array ───────────────────
    static int[] twoSumSorted(int[] sorted, int target) {
        int lo = 0, hi = sorted.length - 1;
        while (lo < hi) {
            int sum = sorted[lo] + sorted[hi];
            if (sum == target) return new int[]{lo, hi};
            else if (sum < target) lo++; // need larger
            else hi--;                   // need smaller
        }
        return new int[]{-1, -1};
    }

    // ── TWO POINTERS: Remove duplicates in-place ─────────────────
    static int removeDuplicates(int[] sorted) {
        if (sorted.length == 0) return 0;
        int slow = 0;
        for (int fast = 1; fast < sorted.length; fast++)
            if (sorted[fast] != sorted[slow])
                sorted[++slow] = sorted[fast];
        return slow + 1; // new length
    }

    // ── PREFIX SUM: Range sum query ──────────────────────────────
    static int[] buildPrefix(int[] arr) {
        int[] pre = new int[arr.length + 1];
        for (int i = 0; i < arr.length; i++)
            pre[i+1] = pre[i] + arr[i];
        return pre; // pre[i] = sum of arr[0..i-1]
    }
    static int rangeSum(int[] pre, int l, int r) {
        return pre[r+1] - pre[l]; // O(1) query
    }

    // ── KADANE'S: Maximum subarray sum ──────────────────────────
    static int maxSubarraySum(int[] arr) {
        int maxSoFar = arr[0], globalMax = arr[0];
        for (int i = 1; i < arr.length; i++) {
            maxSoFar = Math.max(arr[i], maxSoFar + arr[i]); // extend or restart
            globalMax = Math.max(globalMax, maxSoFar);
        }
        return globalMax;
    }

    // ── KADANE with indices: track start/end of max subarray
    static int[] maxSubarrayWithIndices(int[] arr) {
        int maxSoFar = arr[0], globalMax = arr[0];
        int start = 0, end = 0, tempStart = 0;
        for (int i = 1; i < arr.length; i++) {
            if (arr[i] > maxSoFar + arr[i]) { maxSoFar = arr[i]; tempStart = i; }
            else maxSoFar += arr[i];
            if (maxSoFar > globalMax) { globalMax = maxSoFar; start = tempStart; end = i; }
        }
        return new int[]{globalMax, start, end};
    }

    public static void main(String[] args) {
        System.out.println(Arrays.toString(twoSumSorted(new int[]{2,7,11,15}, 9))); // [0,1]

        int[] dup = {1,1,2,2,3,4,4};
        System.out.println(removeDuplicates(dup) + " unique"); // 4 unique

        int[] arr = {3,1,4,1,5,9,2,6};
        int[] pre = buildPrefix(arr);
        System.out.println("Sum [1..4] = " + rangeSum(pre, 1, 4)); // 1+4+1+5=11

        System.out.println(maxSubarraySum(new int[]{-2,1,-3,4,-1,2,1,-5,4})); // 6
        System.out.println(Arrays.toString(
            maxSubarrayWithIndices(new int[]{-2,1,-3,4,-1,2,1,-5,4}))); // [6,3,6]
    }
}

