public class Q3 {
    public static int maxWater(int[] height) {
        int lo = 0, hi = height.length - 1, max = 0;
        while (lo < hi) {
            int water = (hi - lo) * Math.min(height[lo], height[hi]);
            max = Math.max(max, water);
            if (height[lo] < height[hi]) lo++; // move smaller side
            else hi--;
        }
        return max;
    }
    public static void main(String[] args) {
        System.out.println(maxWater(new int[]{1,8,6,2,5,4,8,3,7})); // 49
        System.out.println(maxWater(new int[]{1,1}));                // 1
    }
}
